@auth_bp.route('/admin/users', methods=['GET'])
@login_required
def users_page():
    return render_template('admin/users.html', users=list_users(), current_user=get_current_user())


@auth_bp.route('/api/users', methods=['GET'])
@login_required
def api_users():
    users = [_user_to_dict(user) for user in list_users()]
    return jsonify({'success': True, 'users': users})

def list_users():
    db = get_db()
    return db.execute(
        'SELECT user_id, username, display_name, created_at FROM users ORDER BY user_id ASC'
    ).fetchall()
